  to: phoneTo,
  type: "text",
  text: {
    body: messageText,
    preview_url: true
  }
};

const items = $input.all();

// 1. Filtrar booleanos en JS (Supabase v1 no filtra bien booleanos)
const filtrados = items.filter(item => {
  const d = item.json;
  const followUpSent = d.follow_up_sent === true || d.follow_up_sent === 'true';
  const responded = d.responded === true || d.responded === 'true';

  // Solo traer los que NO tienen follow_up_sent y NO respondieron
  return !followUpSent && !responded;
});

console.log(`[1er Toque] Total traídos: ${items.length}, Después de filtrar: ${filtrados.length}`);

if (filtrados.length === 0) return [];

// 2. Deduplicar por teléfono quedándose con el más reciente
const porTelefono = {};
for (const item of filtrados) {
  const phone = item.json.phone;
  if (!porTelefono[phone]) {
    porTelefono[phone] = item;
  } else {
    const actual = new Date(porTelefono[phone].json.last_bot_message_at);
    const nuevo = new Date(item.json.last_bot_message_at);
    if (nuevo > actual) {
      porTelefono[phone] = item;
    }
  }
}

// 3. Ordenar por last_bot_message_at ascendente (el más viejo primero)
const deduplicados = Object.values(porTelefono);
deduplicados.sort((a, b) => {
  const fechaA = new Date(a.json.last_bot_message_at || 0);
  const fechaB = new Date(b.json.last_bot_message_at || 0);
  return fechaA - fechaB;
});

console.log(`[1er Toque] Después de deduplicar: ${deduplicados.length}, Enviando a: ${deduplicados[0]?.json?.phone}`);

// 4. Tomar SOLO el primero (1 por ejecución)
return [deduplicados[0]];

